function ws_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function ws_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function ws_t($key,$fallback=''){return lang_text($key,$fallback);}
function ws_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function ws_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;}
function ws_c($v){return strtoupper(trim((string)$v));}
function ws_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
function ws_num($v){return is_numeric($v)?(float)$v:0;}
function ws_int($v){return is_numeric($v)?(int)$v:0;}
function ws_bool($v){return in_array($v,array('Y','N'),true);}
function ws_date_ok($v){return (bool)preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$v);}
function ws_time($v){$v=trim((string)$v);if($v==='')return null;if(preg_match('/^\d{2}:\d{2}$/',$v))return $v.':00';if(preg_match('/^\d{2}:\d{2}:\d{2}$/',$v))return $v;ws_json('error','Format jam harus HH:MM atau HH:MM:SS.');}
function ws_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function ws_row($id){global $db;return $db->fetch("SELECT ws.*,s.kode_shift,s.nama_shift,s.jam_mulai,s.jam_selesai,fc.calendar_name,fc.plant_code,wl.location_code,wl.location_name,wl.location_type,d.nm_dept,d.dept_type FROM erp_work_schedule ws LEFT JOIN erp_shift s ON s.id=ws.default_shift_id LEFT JOIN erp_factory_calendar_header fc ON fc.id=ws.calendar_id LEFT JOIN erp_work_location wl ON wl.id=ws.work_location_id LEFT JOIN dept d ON d.kd_dept=ws.department_code WHERE ws.id=? LIMIT 1",array((int)$id));}
function ws_payload($r){$d=(array)$r;$d['calendar_text']=$r->calendar_id?($r->calendar_code.' - '.$r->calendar_name.($r->plant_code?' ['.$r->plant_code.']':'')):'';$d['default_shift_text']=$r->default_shift_id?($r->kode_shift.' - '.$r->nama_shift.' ('.substr($r->jam_mulai,0,5).'-'.substr($r->jam_selesai,0,5).')'):'';$d['work_location_text']=$r->work_location_id?($r->location_code.' - '.$r->location_name.' ['.$r->location_type.']'):'';$d['department_text']=$r->department_code?($r->department_code.' - '.$r->nm_dept.' ['.$r->dept_type.']'):'';$d['planned_start']=$r->planned_start?substr($r->planned_start,0,5):'';$d['planned_end']=$r->planned_end?substr($r->planned_end,0,5):'';return $d;}
function ws_rows($from,$to,$type,$cat,$dept,$status,$kw){global $db;$w=" WHERE ws.valid_from<=? AND ws.valid_to>=? ";$p=array($to,$from);if($type!==''){$w.=" AND ws.schedule_type=? ";$p[]=$type;}if($cat!==''){$w.=" AND ws.schedule_category=? ";$p[]=$cat;}if($dept!==''){$w.=" AND ws.department_code=? ";$p[]=$dept;}if($status!==''){$w.=" AND ws.schedule_status=? ";$p[]=$status;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (ws.schedule_code LIKE ? OR ws.schedule_name LIKE ? OR ws.sap_reference LIKE ? OR ws.remarks LIKE ? OR wl.location_code LIKE ? OR wl.location_name LIKE ? OR d.nm_dept LIKE ?) ";array_push($p,$like,$like,$like,$like,$like,$like,$like);}return $db->query("SELECT ws.*,s.kode_shift,s.nama_shift,s.jam_mulai,s.jam_selesai,fc.calendar_name,fc.plant_code,wl.location_code,wl.location_name,wl.location_type,d.nm_dept,d.dept_type FROM erp_work_schedule ws LEFT JOIN erp_shift s ON s.id=ws.default_shift_id LEFT JOIN erp_factory_calendar_header fc ON fc.id=ws.calendar_id LEFT JOIN erp_work_location wl ON wl.id=ws.work_location_id LEFT JOIN dept d ON d.kd_dept=ws.department_code $w ORDER BY ws.schedule_category,ws.schedule_code",$p);}

