  $rows=$db->query("SELECT id,kode_shift,nama_shift,jam_mulai,jam_selesai FROM erp_shift WHERE status='Aktif' AND (?='' OR kode_shift LIKE ? OR nama_shift LIKE ?) ORDER BY kode_shift LIMIT 30",array($t,$like,$like));
