  if($code==='')ws_json('error','Schedule Code wajib diisi.');if(!preg_match('/^[A-Z0-9_-]{3,30}$/',$code))ws_json('error','Schedule Code hanya boleh huruf besar, angka, underscore, atau dash.');if($name==='')ws_json('error','Schedule Name wajib diisi.');if(!in_array($type,$types,true))ws_json('error','Schedule Type tidak valid.');if(!in_array($cat,$cats,true))ws_json('error','Schedule Category tidak valid.');if(!in_array($group,$groups,true))ws_json('error','Employee Group tidak valid.');if(!in_array($status,$stats,true))ws_json('error','Status tidak valid.');
  $from=trim(ws_p('valid_from','2026-01-01'));$to=trim(ws_p('valid_to','9999-12-31'));if(!ws_date_ok($from)||!ws_date_ok($to))ws_json('error','Valid From/To wajib format YYYY-MM-DD.');if(strtotime($to)<strtotime($from))ws_json('error','Valid To tidak boleh sebelum Valid From.');
  $days=array('monday','tuesday','wednesday','thursday','friday','saturday','sunday');$dayData=array();foreach($days as $d){$v=ws_c(ws_p($d,'N'));if(!ws_bool($v))ws_json('error','Working day '.$d.' tidak valid.');$dayData[$d]=$v;}
