  $calId=ws_p('calendar_id')!==''?(int)ws_p('calendar_id'):null;$calCode=null;if($calId){$cal=$db->fetch("SELECT id,calendar_code FROM erp_factory_calendar_header WHERE id=? LIMIT 1",array($calId));if(!$cal)ws_json('error','Factory Calendar tidak valid.');$calCode=$cal->calendar_code;}
