  $dept=ws_p('department_code')!==''?ws_c(ws_p('department_code')):null;if($dept&&!$db->fetch("SELECT kd_dept FROM dept WHERE kd_dept=? LIMIT 1",array($dept)))ws_json('error','Department tidak valid.');
