  if(!$ok)ws_json('error',$db->getErrorMessage()?:ws_t('work_schedule_error_default','Work Schedule failed to process.'));if(function_exists('simpan_log'))simpan_log('User '.$username.' menyimpan Work Schedule '.$code.' untuk kategori '.$cat.' pada '.date('Y-m-d H:i:s'),$username);ws_json('good',ws_t('work_schedule_saved_message','Work Schedule saved successfully.'),array('id'=>$id));
